+              AllConst = false;
+              break;
+            }
+          }
+        }
+        if (AllConst) {
+          // Ignore instructions already represented explicitly in the VPlan;
+          // they are not "additional".
+          if (!SeenInstrs.contains(&I))
+            HasConstFoldable = true;
+        }
+      }
+      if (HasMissingOrSkipped || HasConstFoldable)
+        break;
+    }
+    if (HasMissingOrSkipped || HasConstFoldable)
